import React from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';

/** @type {typeof import('../..').Widther<any>} */
const Widther = (WrappedComponent) => {
  /** @extends React.PureComponent<import('../..').WidtherProps> */
  class WidtherHOC extends React.PureComponent {
    render() {
      let { className } = this.props;
      const { width } = this.props;
      if (width) {
        className = classNames(className, `andes-width--${width}`);
      }
      return width !== null ? (
        <div key="widther" className="andes-widther">
          <WrappedComponent
            {...this.props}
            className={className}
          />
        </div>
      ) : <WrappedComponent key="widther" {...this.props} />;
    }
  }

  WidtherHOC.propTypes = {
    ...WrappedComponent.propTypes,
    className: PropTypes.string,
    width: PropTypes.oneOf([25, 50, 75, 100, 150, 200]),
  };

  WidtherHOC.displayName = WrappedComponent.displayName || 'WidtherHOC';

  return WidtherHOC;
};

export default Widther;
